import React, { useState, useEffect } from 'react';
import { Card, Typography, Button, Tag, Empty, Alert, Form, Input, Checkbox, Space, Row, Col } from 'antd';
import { DeleteOutlined, ArrowLeftOutlined, CheckCircleOutlined, ExclamationCircleOutlined } from '@ant-design/icons';
import ApiService from '../services/api';
import { BRAND_COLORS } from '../constants/theme';

function BranchStaff() {
  const [tasks, setTasks] = useState([]);
  const [selectedTask, setSelectedTask] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [formData, setFormData] = useState({
    isFCR: false,
    fcrComments: ''
  });
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [message, setMessage] = useState('');
  const [clearingTasks, setClearingTasks] = useState(false);

  useEffect(() => {
    loadTasks();
  }, []);

  const loadTasks = async () => {
    try {
      setLoading(true);
      // Get tasks assigned to "initiator" since that's what the BPMN process uses
      const tasksData = await ApiService.getEnrichedTasks();
      // Filter for Branch Staff tasks (Register Complaint and First Contact Resolution)
      const branchTasks = tasksData.filter(task => 
        task.name && (
          task.name.includes('First Contact Resolution') || 
          task.name.includes('FIrst Contact Resolution') ||
          task.name.includes('Register Complaint') ||
          task.definitionKey === 'FormTask_72'
        )
      );
      setTasks(branchTasks);
    } catch (error) {
      setError('Failed to load tasks');
      console.error('Error loading tasks:', error);
    } finally {
      setLoading(false);
    }
  };

  const clearAllTasks = async () => {
    if (window.confirm('Are you sure you want to clear all tasks? This action cannot be undone.')) {
      setClearingTasks(true);
      try {
        // Get all tasks and complete them
        const allTasks = await ApiService.getTasks();
        const clearPromises = allTasks.map(task => 
          ApiService.completeTask(task.id, {})
        );

        await Promise.all(clearPromises);
        setMessage('All tasks cleared successfully!');
        setSelectedTask(null);
        setFormData({ isFCR: false, fcrComments: '' });
        await loadTasks();

        // Clear success message after 3 seconds
        setTimeout(() => setMessage(''), 3000);
      } catch (error) {
        setMessage('Failed to clear some tasks');
        console.error('Error clearing tasks:', error);
      } finally {
        setClearingTasks(false);
      }
    }
  };

  const handleTaskSelect = async (task) => {
    setSelectedTask(task);
    setMessage('');
    try {
      // Task is already assigned to "initiator", no need to claim
      // Just proceed with task selection
      await loadTasks(); // Reload tasks to update status
    } catch (error) {
      setMessage('Failed to select task');
      console.error('Error selecting task:', error);
    }
  };

  const handleFormChange = (e) => {
    const { name, value, type, checked } = e.target;
    setFormData(prev => ({
      ...prev,
      [name]: type === 'checkbox' ? checked : value
    }));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!selectedTask) return;

    setIsSubmitting(true);
    setMessage('');

    try {
      const variables = {
        isFCR: formData.isFCR,
        fcrComments: formData.fcrComments || ''
      };

      await ApiService.completeTask(selectedTask.id, variables);

      if (formData.isFCR) {
        setMessage('Task completed! Complaint resolved and customer will be notified.');
      } else {
        setMessage('Task completed! Complaint has been escalated to CMD for screening.');
      }

      // Reset form and reload tasks
      setFormData({ isFCR: false, fcrComments: '' });
      setSelectedTask(null);
      await loadTasks();
    } catch (error) {
      setMessage('Failed to complete task');
      console.error('Error completing task:', error);
    } finally {
      setIsSubmitting(false);
    }
  };

  if (loading) return (
    <div style={{ display: 'flex', justifyContent: 'center', alignItems: 'center', height: '400px' }}>
      <Card loading={true} style={{ width: '100%', maxWidth: '600px' }} />
    </div>
  );

  if (error) return (
    <Alert
      message="Error"
      description={error}
      type="error"
      showIcon
      style={{ margin: '20px' }}
    />
  );

  const getPriorityColor = (priority) => {
    switch (priority?.toLowerCase()) {
      case 'p1': return 'red';
      case 'p2': return 'orange';
      case 'p3': return 'green';
      default: return 'blue';
    }
  };

  const getSlaStatusColor = (status) => {
    switch (status?.toLowerCase()) {
      case 'overdue': return 'error';
      case 'approaching': return 'warning';
      default: return 'success';
    }
  };

  return (
    <div style={{ maxWidth: '1200px', margin: '0 auto' }}>
      {/* Header */}
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '32px' }}>
        <div>
          <Title level={2} style={{ margin: 0, color: BRAND_COLORS.primary }}>
            Branch Staff Tasks
          </Title>
          <Text type="secondary" style={{ fontSize: '16px' }}>
            Manage and resolve customer complaints
          </Text>
        </div>
        <Button
          danger
          icon={<DeleteOutlined />}
          onClick={clearAllTasks}
          disabled={clearingTasks}
          loading={clearingTasks}
          size="large"
        >
          Clear All Tasks
        </Button>
      </div>

      {message && (
        <Alert
          message={message.includes('success') ? 'Success' : 'Information'}
          description={message}
          type={message.includes('success') ? 'success' : 'info'}
          showIcon
          closable
          style={{ marginBottom: '24px' }}
          onClose={() => setMessage('')}
        />
      )}

      {!selectedTask ? (
        <div>
          {tasks.length === 0 ? (
            <Empty
              description="No tasks available"
              image={Empty.PRESENTED_IMAGE_SIMPLE}
              style={{ marginTop: '60px' }}
            />
          ) : (
            <Row gutter={[24, 24]}>
              {tasks.map(task => (
                <Col xs={24} sm={24} md={12} lg={8} xl={6} key={task.id}>
                  <Card
                    hoverable
                    className={`task-card task-priority-${getPriorityColor(task.priority)}`}
                    onClick={() => handleTaskSelect(task)}
                    size="small"
                    title={
                      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                        <Text strong style={{ fontSize: '14px' }}>
                          {task.name}
                        </Text>
                        <Tag color={getSlaStatusColor(task.slaStatus)}>
                          {task.slaStatus}
                        </Tag>
                      </div>
                    }
                    extra={
                      <Tag color={getPriorityColor(task.priority)}>
                        {task.priority}
                      </Tag>
                    }
                  >
                    <Space direction="vertical" size="small" style={{ width: '100%' }}>
                      <div>
                        <Text type="secondary">Ticket ID:</Text>
                        <br />
                        <Text code>{task.complaintId}</Text>
                      </div>
                      <div>
                        <Text type="secondary">Customer:</Text>
                        <br />
                        <Text>{task.customerName}</Text>
                      </div>
                      <div>
                        <Text type="secondary">Created:</Text>
                        <br />
                        <Text>{new Date(task.createdAt).toLocaleDateString()}</Text>
                      </div>
                    </Space>
                  </Card>
                </Col>
              ))}
            </Row>
          )}
        </div>
      ) : (
        <div>
          <Button
            icon={<ArrowLeftOutlined />}
            onClick={() => setSelectedTask(null)}
            style={{ marginBottom: '24px' }}
          >
            Back to Tasks
          </Button>

          <h3>Task Details</h3>
          <div style={{
            border: '1px solid #ddd',
            borderRadius: '4px',
            padding: '15px',
            marginBottom: '20px',
            backgroundColor: '#f9f9f9'
          }}>
            <h4>Complaint Information</h4>
            <p><strong>Ticket ID:</strong> {selectedTask.complaintId}</p>
            <p><strong>Customer Name:</strong> {selectedTask.customerName}</p>
            <p><strong>Priority:</strong> {selectedTask.priority}</p>
            <p><strong>SLA Status:</strong> {selectedTask.slaStatus}</p>

            {selectedTask.variables?.complaint && (
              <div>
                <p><strong>Description:</strong></p>
                <p style={{ fontStyle: 'italic' }}>{selectedTask.variables.complaint.description}</p>
              </div>
            )}
          </div>

          <form onSubmit={handleSubmit}>
            <h4>Branch Resolution</h4>

            <div style={{ marginBottom: '15px' }}>
              <label style={{ display: 'block', marginBottom: '5px' }}>
                <input
                  type="checkbox"
                  name="isFCR"
                  checked={formData.isFCR}
                  onChange={handleFormChange}
                  style={{ marginRight: '8px' }}
                />
                Resolved at first contact?
              </label>
              <small>If checked, the complaint will be closed. If not, it will be sent to CMD.</small>
            </div>

            <div style={{ marginBottom: '15px' }}>
              <label style={{ display: 'block', marginBottom: '5px' }}>
                FCR Comments (optional)
              </label>
              <textarea
                name="fcrComments"
                value={formData.fcrComments}
                onChange={handleFormChange}
                rows={3}
                placeholder="Enter resolution details or comments..."
                style={{
                  width: '100%',
                  padding: '8px',
                  border: '1px solid #ddd',
                  borderRadius: '4px',
                  resize: 'vertical'
                }}
              />
            </div>

            <button
              type="submit"
              disabled={isSubmitting}
              style={{
                backgroundColor: '#007bff',
                color: 'white',
                padding: '10px 20px',
                border: 'none',
                borderRadius: '4px',
                cursor: isSubmitting ? 'not-allowed' : 'pointer',
                opacity: isSubmitting ? 0.7 : 1,
                marginRight: '10px'
              }}
            >
              {isSubmitting ? 'Processing...' : formData.isFCR ? 'Resolve and Close' : 'Send to CMD'}
            </button>
          </form>
        </div>
      )}
    </div>
  );
}

export default BranchStaff;
